tinymce.PluginManager.add('gallery', function(editor, url) {
    editor.ui.registry.addIcon('gallery', '<?xml version="1.0" encoding="utf-8"?>\n' +
        '<!-- Generator: Adobe Illustrator 16.0.0, SVG Export Plug-In . SVG Version: 6.00 Build 0)  -->\n' +
        '<!DOCTYPE svg PUBLIC "-//W3C//DTD SVG 1.1//EN" "http://www.w3.org/Graphics/SVG/1.1/DTD/svg11.dtd">\n' +
        '<svg version="1.1" id="Layer_1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" x="0px" y="0px"\n' +
        '\t width="20px" height="19px" viewBox="0 0 20 19" enable-background="new 0 0 20 19" xml:space="preserve">\n' +
        '<g>\n' +
        '\t<g>\n' +
        '\t\t<path fill-rule="evenodd" clip-rule="evenodd" d="M11,11l-2,2L5,8l-3,8h12L11,11z M12.5,10c0.828,0,1.5-0.671,1.5-1.5\n' +
        '\t\t\tS13.328,7,12.5,7S11,7.671,11,8.5S11.672,10,12.5,10z M4,1v2H2v2H0v13h16v-2h2v-2h2V1H4z M15,17H1V6h14V17z M17,15h-1V5H3V4h14V15\n' +
        '\t\t\tz M19,13h-1V3H5V2h14V13z"/>\n' +
        '\t</g>\n' +
        '</g>\n' +
        '</svg>');

    var openDialog = function () {
        var cid = editor.getParam('content_id');
        var ctype = editor.getParam('content_type');
        var module_code = editor.getParam('module_code');
        var query = '?cid='+cid+'&ctype='+ctype+'&moduleCode='+module_code;
        return editor.windowManager.openUrl({
            url: tinymce.baseURL + '/plugins/gallery/scripts/gallery.php'+query,
            title: 'Gallery',
            width: 350,
            height: 370,
        });
    };

    editor.ui.registry.addButton('gallery', {
        tooltip: 'Gallery',
        icon: 'gallery',
        onAction: function () {
            // Open window
            openDialog();
        }

    });

    // Adds a menu item, which can then be included in any menu via the menu/menubar configuration
    editor.ui.registry.addMenuItem('gallery', {
        text: 'Gallery',
        icon: 'gallery',
        onAction: function () {
            // Open window
            openDialog();
        }
    });
});